import{_ as o,o as r,c as a,ag as t}from"./chunks/framework.DGzMGr_a.js";const h=JSON.parse('{"title":"Buffer 与二进制数据","description":"","frontmatter":{"title":"Buffer 与二进制数据","difficulty":"medium","tags":["Buffer","二进制","TypedArray"],"estimate":20},"headers":[],"relativePath":"domains/nodejs/qa/qa-06-buffer.md","filePath":"domains/nodejs/qa/qa-06-buffer.md","lastUpdated":1783504823000}'),l={name:"domains/nodejs/qa/qa-06-buffer.md"};function f(n,e,d,c,s,i){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="问答-06-进阶-buffer-与二进制数据" tabindex="-1">问答 06（进阶）：Buffer 与二进制数据 <a class="header-anchor" href="#问答-06-进阶-buffer-与二进制数据" aria-label="Permalink to &quot;问答 06（进阶）：Buffer 与二进制数据&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>Buffer 是什么？为什么 Node.js 需要它？它和字符串、TypedArray 有什么关系？使用时有哪些坑？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>Buffer 是什么</strong></p><ul><li>Buffer 是 Node 中处理 <strong>二进制数据</strong> 的类，代表一段固定长度的原始内存（V8 堆外分配）。</li><li>用于处理文件、网络包、图片、加密等非文本或需要精确字节控制的数据。</li></ul><p><strong>为什么需要</strong></p><ul><li>JS 原生字符串是 UTF-16 文本，无法安全表达任意二进制字节；网络和文件本质是字节流，需要 Buffer 来读写。</li></ul><p><strong>与字符串的关系</strong></p><ul><li>字符串 ↔ Buffer 通过编码转换：<code>Buffer.from(str, &#39;utf8&#39;)</code>、<code>buf.toString(&#39;utf8&#39;)</code>。常见编码：utf8、base64、hex、ascii、latin1。</li><li>一个字符可能占多个字节（如中文 UTF-8 占 3 字节），<strong>按字节切割 Buffer 可能截断多字节字符</strong>导致乱码。</li></ul><p><strong>与 TypedArray 的关系</strong></p><ul><li>Buffer 是 <code>Uint8Array</code> 的子类，底层是 <code>ArrayBuffer</code>，因此可与 <code>TypedArray</code>、<code>DataView</code> 互操作。</li></ul><p><strong>常见坑</strong></p><ul><li><strong>不要用 <code>new Buffer()</code></strong>（已废弃且不安全，可能返回未清零内存）。用 <code>Buffer.alloc(size)</code>（清零）、<code>Buffer.allocUnsafe(size)</code>（不清零，更快但内容随机）、<code>Buffer.from(...)</code>。</li><li>拼接多块时用 <code>Buffer.concat([...])</code>，别转成字符串再拼（会乱码/丢字节）。</li></ul><h2 id="追问-1-buffer-alloc-和-buffer-allocunsafe-有什么区别-何时用哪个" tabindex="-1">追问 1：<code>Buffer.alloc</code> 和 <code>Buffer.allocUnsafe</code> 有什么区别？何时用哪个？ <a class="header-anchor" href="#追问-1-buffer-alloc-和-buffer-allocunsafe-有什么区别-何时用哪个" aria-label="Permalink to &quot;追问 1：`Buffer.alloc` 和 `Buffer.allocUnsafe` 有什么区别？何时用哪个？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><code>Buffer.alloc(n)</code>：分配并<strong>填充 0</strong>，安全，稍慢。</li><li><code>Buffer.allocUnsafe(n)</code>：仅分配不清零，可能包含旧内存中的<strong>敏感残留数据</strong>，更快。</li><li>用 unsafe 时必须保证<strong>立即完整覆盖</strong>所有字节（比如马上被读入数据填满），否则有信息泄露风险。对性能敏感且能保证全覆盖时用 unsafe，否则用 alloc。</li></ul><h2 id="追问-2-处理流式数据时-为什么直接对每个-chunk-调用-tostring-拼接可能出乱码-如何正确处理" tabindex="-1">追问 2：处理流式数据时，为什么直接对每个 chunk 调用 <code>toString()</code> 拼接可能出乱码？如何正确处理？ <a class="header-anchor" href="#追问-2-处理流式数据时-为什么直接对每个-chunk-调用-tostring-拼接可能出乱码-如何正确处理" aria-label="Permalink to &quot;追问 2：处理流式数据时，为什么直接对每个 chunk 调用 `toString()` 拼接可能出乱码？如何正确处理？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>因为一个多字节字符（如中文）可能被拆分到两个 chunk 的边界，单独 <code>toString</code> 每个 chunk 会把半个字符解码成乱码。</li><li>正确做法： <ol><li>先把所有 chunk 收集成数组，最后 <code>Buffer.concat</code> 再一次性 <code>toString</code>；</li><li>或使用 <code>string_decoder</code> 模块的 <code>StringDecoder</code>，它会缓存不完整的多字节字符，跨 chunk 正确拼接。</li></ol></li></ul><h2 id="追问-3-buffer-内存是分配在-v8-堆上吗-这对内存管理有什么影响" tabindex="-1">追问 3：Buffer 内存是分配在 V8 堆上吗？这对内存管理有什么影响？ <a class="header-anchor" href="#追问-3-buffer-内存是分配在-v8-堆上吗-这对内存管理有什么影响" aria-label="Permalink to &quot;追问 3：Buffer 内存是分配在 V8 堆上吗？这对内存管理有什么影响？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>Buffer 的底层内存分配在 <strong>V8 堆外</strong>（off-heap，由 Node 直接管理），不受 <code>--max-old-space-size</code> 限制，但受进程总内存限制。</li><li>影响：大量或大 Buffer 不计入 V8 老生代堆，但仍占进程 RSS；如果持有大量 Buffer 引用（比如缓存），可能造成 RSS 飙高却不触发 V8 GC 压力，排查内存泄漏时要同时看 heap 和 RSS/外部内存（<code>process.memoryUsage().external</code>）。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/api/buffer.html" target="_blank" rel="noreferrer">Node.js: Buffer</a>：<code>alloc</code>/<code>allocUnsafe</code>、编码转换与堆外内存说明。</li><li><a href="https://nodejs.org/api/string_decoder.html" target="_blank" rel="noreferrer">Node.js: string_decoder</a>：跨 chunk 多字节字符解码，避免流式 <code>toString</code> 乱码。</li><li><a href="https://nodejs.org/api/stream.html" target="_blank" rel="noreferrer">Node.js: Stream</a>：Buffer 与可读/可写流配合处理二进制数据。</li></ul>',26)])])}const g=o(l,[["render",f]]);export{h as __pageData,g as default};
